import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function Login() {
    const { login } = useAuth();
    const navigate = useNavigate();

    const [form, setForm] = useState({ email: '', password: '' });
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleChange = e => setForm(p => ({ ...p, [e.target.name]: e.target.value }));

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!form.email || !form.password) {
            setError('Please enter your email and password.');
            return;
        }
        setLoading(true);
        setError('');
        const res = await login(form.email, form.password);
        setLoading(false);
        if (res.success) {
            navigate('/dashboard');
        } else {
            setError(res.message);
        }
    };

    return (
        <div className="min-h-screen bg-dark-900 flex items-center justify-center px-4 relative overflow-hidden">
            {/* Background glow blobs */}
            <div className="absolute inset-0 pointer-events-none">
                <div className="absolute -top-40 -left-40 w-96 h-96 rounded-full
                        bg-primary-600/20 blur-[120px]" />
                <div className="absolute -bottom-40 -right-40 w-96 h-96 rounded-full
                        bg-accent-600/20 blur-[120px]" />
            </div>

            <div className="w-full max-w-md relative z-10 animate-fadeInUp">
                {/* Logo */}
                <div className="flex flex-col items-center mb-8">
                    <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-primary-500 to-accent-500
                          flex items-center justify-center shadow-neon-blue mb-4">
                        <svg className="w-7 h-7 text-white" fill="none" viewBox="0 0 24 24"
                            stroke="currentColor" strokeWidth={2}>
                            <path strokeLinecap="round" strokeLinejoin="round"
                                d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z" />
                            <path strokeLinecap="round" strokeLinejoin="round"
                                d="M19 10v2a7 7 0 0 1-14 0v-2M12 19v4M8 23h8" />
                        </svg>
                    </div>
                    <h1 className="font-display font-bold text-3xl text-white tracking-tight">UnMute</h1>
                    <p className="text-white/40 text-sm mt-1">Turn Your Voice On</p>
                </div>

                {/* Card */}
                <div className="glass-card p-8">
                    <h2 className="text-xl font-display font-bold text-white mb-1">Welcome back</h2>
                    <p className="text-white/40 text-sm mb-6">Sign in to continue practicing</p>

                    {error && (
                        <div className="mb-4 px-4 py-3 rounded-xl bg-red-500/10 border border-red-500/30">
                            <p className="text-red-400 text-sm">{error}</p>
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div>
                            <label htmlFor="email" className="label-text">Email address</label>
                            <input
                                id="email" name="email" type="email" autoComplete="email"
                                className="input-field"
                                placeholder="you@example.com"
                                value={form.email}
                                onChange={handleChange}
                                required
                            />
                        </div>

                        <div>
                            <label htmlFor="password" className="label-text">Password</label>
                            <input
                                id="password" name="password" type="password" autoComplete="current-password"
                                className="input-field"
                                placeholder="••••••••"
                                value={form.password}
                                onChange={handleChange}
                                required
                            />
                        </div>

                        <button type="submit" disabled={loading} className="btn-primary w-full justify-center mt-2
                   disabled:opacity-50 disabled:cursor-not-allowed">
                            {loading ? (
                                <span className="flex items-center justify-center gap-2">
                                    <span className="w-4 h-4 rounded-full border-2 border-white/30 border-t-white animate-spin" />
                                    Signing in…
                                </span>
                            ) : 'Sign In'}
                        </button>
                    </form>

                    {/* Divider */}
                    <div className="flex items-center gap-3 my-5">
                        <span className="flex-1 h-px bg-white/10" />
                        <span className="text-white/30 text-xs">or</span>
                        <span className="flex-1 h-px bg-white/10" />
                    </div>

                    {/* Demo credentials info */}
                    <div className="p-3 rounded-xl bg-primary-600/10 border border-primary-500/20 mb-4">
                        <p className="text-primary-400 text-xs font-medium mb-1">🧪 Demo Credentials</p>
                        <p className="text-white/50 text-xs">Email: <span className="text-white">demo@unmute.app</span></p>
                        <p className="text-white/50 text-xs">Password: <span className="text-white">Demo@1234</span></p>
                    </div>

                    <p className="text-center text-sm text-white/40">
                        Don't have an account?{' '}
                        <Link to="/register" className="text-primary-400 hover:text-primary-300 font-medium transition-colors">
                            Sign up free
                        </Link>
                    </p>
                </div>
            </div>
        </div>
    );
}
